@startuml
skinparam classBoxStyle fillcolor: #f0f0f0, border: 1px solid #666
skinparam actorStyle fillcolor: #e0e0e0, border: 1px solid #666

actor "Dispatcher" as D1
actor "Dispatcher" as D2

actor "JobManagerRunner_JobMaster" as JMR1
actor "JobManagerRunner_JobMaster" as JMR2

actor "SchedulerNG" as SN1
actor "SchedulerNG" as SN2

rectangle "Dispatcher" {
    D1
    D2
}

rectangle "JobManagerRunner_JobMaster" {
    JMR1
    JMR2
}

rectangle "SchedulerNG" {
    SN1
    SN2
}

D1 ..> JMR1 : jobManagerRunnerFactory.createJobManagerRunner
JMR1 ..> SN1 : SlotPoolService.SchedulerFactory.createScheduler

@enduml
